import { useEffect, useMemo, useRef, useState } from 'react';
import type { ActionEvent, ActionStatus } from '@/types/actions';

type Options = {
  /** Optional: provide when you know the server start time */
  startedAt?: string;
  /** Poll interval in ms */
  intervalMs?: number;
};

const TERMINAL: ActionStatus[] = ['SUCCEEDED', 'FAILED', 'CANCELED'];

/** Mock‑friendly task polling. If no backend is available, simulates progress. */
export function useActionTask(taskId?: string, opts: Options = {}) {
  const [events, setEvents] = useState<ActionEvent[]>([]);
  const [status, setStatus] = useState<ActionStatus>('PENDING');
  const [done, setDone] = useState(false);
  const startRef = useRef<number | null>(null);
  const intervalMs = opts.intervalMs ?? 2000;

  const startedAtIso = useMemo(() => {
    if (opts.startedAt) return opts.startedAt;
    // First time we see a taskId, record local start
    if (taskId && startRef.current == null) startRef.current = Date.now();
    return startRef.current ? new Date(startRef.current).toISOString() : new Date().toISOString();
  }, [taskId, opts.startedAt]);

  useEffect(() => {
    if (!taskId) {
      setEvents([]);
      setStatus('PENDING');
      setDone(false);
      return;
    }

    let stop = false;
    async function tick() {
      if (stop) return;
      // If you expose GET /api/actions/{id}/events, fetch it here instead
      // For now, simulate a short timeline: 0s PENDING, 1s RUNNING, 5s SUCCEEDED
      const start = startRef.current ?? Date.now();
      const elapsed = (Date.now() - start) / 1000;
      const sim: ActionEvent[] = [
        { id: `${taskId}:0`, status: 'PENDING', ts: new Date(start).toISOString(), message: 'Task accepted' },
      ];
      if (elapsed >= 1) sim.push({ id: `${taskId}:1`, status: 'RUNNING', ts: new Date(start + 1000).toISOString(), message: 'Executing' });
      if (elapsed >= 5) sim.push({ id: `${taskId}:2`, status: 'SUCCEEDED', ts: new Date(start + 5000).toISOString(), message: 'Completed' });

      setEvents(sim);
      const last = sim[sim.length - 1]?.status ?? 'PENDING';
      setStatus(last);
      setDone(TERMINAL.includes(last));
    }

    tick();
    const id = window.setInterval(tick, intervalMs);
    return () => { stop = true; window.clearInterval(id); };
  }, [taskId, intervalMs, startedAtIso]);

  return { taskId, startedAt: startedAtIso, events, status, done };
}

export default useActionTask;
